<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('CDCCode') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>

                    </div>
                    <div class="modal-body">
                        <tg-list :IsShowAction="true" ModuleName="Billing" SubModuleCode="Area" :LegendArray="[]"
                            :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" :widgets="[]"
                            IdentityColumn="CDC_ID" :listType="['List']" :ListData="ListData" :HeaderData="Headers"
                            :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords"  :ListDataCallBackFunction="FetchData"
                            :showCheckBox="showCheckBox" :SortExp="SortExp" :SortBy="SortBy"
                            :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="leftCommonSearch"
                            v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
                            v-on:SortdataButtonClick="sortdata" v-on:CheckboxChange="onCheckboxChange">
                                <template v-slot:slotdata="{ data }">
                                <template v-if="data.column.COLUMN_NAME == 'ISAH'">
                                    <span>{{ data.row.ISAH ? 'Yes' : 'No' }}</span>
                                </template>
                                <template v-if="data.column.COLUMN_NAME == 'ISWIRECENTER'">
                                    <span>{{ data.row.ISWIRECENTER ? 'Yes' : 'No' }}</span>
                                </template>
                            </template>
                        </tg-list>
                    </div>  
                </div>
            </div>
        </div>
    </div>
</template> 
<script>
import { locateBillingService } from "../../../services/locateBillingService";
export default {
    props: {
        ClientId: {
            type: Object,
            required: true
        },
        additionalId: {
            type: Object,
            required: true
        },
        TermCode: {
            type: String,
            required: true
        }
    },
    data() {
        return {
            isLoading: false,
            HeaderText: '',
            listheaderbuttons: [
                {
                    text: "<i class='fa fa-plus pr-2'></i>" + this.$t('AddNew'),
                    class: "btn btn-primary",
                    callbackfunction: 'AddCDCCode',
                    isdisabled: false
                },
                {
                    text: "<i class='fa fa-trash pr-2'></i>" + this.$t('Deleterecord'),
                    class: "btn btn-danger",
                    callbackfunction: 'DeleteMultipleCDCCode',
                    isdisabled: true
                }
            ],
            selectedItems: [],
            showCheckBox: true,
            Headers: [{
                "COLUMN_NAME": "CDC_CODE",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'CDC Code',
                "DISPLAY_ORDER": 1,

            },
            {
                "COLUMN_NAME": "SBA_NAME",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'SBA Id',
                "DISPLAY_ORDER": 2
            },
        {
                "COLUMN_NAME": "STATE",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'State',
                "DISPLAY_ORDER": 1,

            },
            {
                "COLUMN_NAME": "ABBREVIATIONS",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Abbreviations',
                "DISPLAY_ORDER": 2
            },
        {
                "COLUMN_NAME": "ISAH",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Is After Hour',
                "DISPLAY_ORDER": 1,

            },
            {
                "COLUMN_NAME": "ISWIRECENTER",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Is Wire Center',
                "DISPLAY_ORDER": 2
            },
        {
                "COLUMN_NAME": "DIVISION_NAME",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Invoice Grouping',
                "DISPLAY_ORDER": 1,

            }],
            SortBy: '',
            SortExp: '',
            TotalRecords: 0,
            searchCondition: '',
            PageNumber: 1,
            PageSize: 10,
            ListData: [],
            CurrentPage: 1,
            TotalPages: 0,
            leftSearchFields: [],
            noRecords:false,
             listActions: [{
                title: 'Edit',
                href: 'javascript:void(0)',
                icon: 'fa fa-pencil text-success action-icon',
                callbackfunction: 'EditCDCCode',
                additionalSpan: ''
            },
            {
                title: 'Status',
                href: 'javascript:void(0)',
                icon: 'fa fa-check text-info action-icon',
                callbackfunction: 'ChangeStatus',
                additionalSpan: ''
            }
            ],
        }
    },
    created: function () {
        var vm = this;
        vm.FetchData();
    },
    methods: {
         renderActions(row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Status':
                        action.isVisible = true;
                        action.icon = row.STATUS_NAME == 'Active' ? 'fa fa-check text-info action-icon' : 'fa fa-check text-secondary action-icon';
                        break;
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        commonHeaderButtonClick: function (callbackfunction) {
            var vm = this;
            switch (callbackfunction) {
                case 'AddCDCCode':
                    vm.AddCDCCode();
                    break;
                case 'DeleteMultipleCDCCode':
                    vm.DeleteMultipleCDCCode();
                    break;
            }
        },
        actionButtonClick(callbackfunction, item, index, event) {
            switch (callbackfunction) {
                case 'EditCDCCode':
                    this.EditCDCCode(item, index);
                    break;
                case 'ChangeStatus':
                    this.UpdateCDCCodeStatus(item, index);
                    break;
            }
        },
        async UpdateCDCCodeStatus(item, index) {
        var vm=this;
        const postJSON = {
            Id: item.CDC_ID,
            StatusId: item.STATUS_NAME=='Active' ? 1002 : 1001,
            TableName: 'TALYGEN_BE_CDC_CODE_INFO',
            PrimaryColumn: 'cdc_id'
        };

        try {
            const response = await locateBillingService.CommonUpdateStatus(postJSON);
            if (response.data.msg === 'Success') {
                this.ShowAlert(this.$t('CDCCodeStatusUpdated'), "success", true, this.$t("Alert"));
                vm.FetchData();
            } else {
                this.ShowAlert(this.$t('DeletedError', [this.$t('WorkCode')]), "failure", true, this.$t("Alert"));
            }
            } catch (error) {
                this.ShowAlert(this.$t('ErrorWhileProcessingRequest'), "failure", true, this.$t("Alert"));
            }
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                this.searchCondition = value.searchConditionJson;
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        FetchData: async function () {
            var vueObj = this;
            var sortBy = vueObj.SortBy || '';
            var sortExp = vueObj.SortExp || '';
            var params = `clientId=${vueObj.ClientId}&rowNo=&additionalId=${vueObj.additionalId}&cdcCode=${vueObj.TermCode}&reqFrom=flagRecords&sortBy=${sortBy}&sortExp=${sortExp}&pageSize=${vueObj.PageSize}&pageNum=${vueObj.PageNumber}`; 
            vueObj.isLoading = true;
            await locateBillingService.GetCDC_CodePagedList(params).then((response) => {
                vueObj.ListData=[];
                if (response.data.length>0) {
                     vueObj.Headers.forEach((column) => {
                        column.settings = null;
                        if (column.COLUMN_NAME == "ISAH" || column.COLUMN_NAME == "ISWIRECENTER") {
                            column.settings = {
                                isInSlot: true,
                            };
                        }
                    });
                    vueObj.ListData = response.data;
                    if (vueObj.ListData.length > 0) {
                        vueObj.TotalRecords = response.data[0].TotalRecords;
                        vueObj.TotalPages = Math.ceil(vueObj.TotalRecords / vueObj.PageSize);
                        vueObj.CurrentPage = vueObj.PageNumber;
                        vueObj.listheaderbuttons[1].isdisabled = true;
                        vueObj.noRecords = false;
                    }
                    else {
                        vueObj.noRecords = true;
                    }
                }
                else {
                    vueObj.noRecords = true;
                    vueObj.TotalRecords = 0
                }
                vueObj.isLoading = false;
            }).catch(error => {
                vueObj.isLoading = false;
                vueObj.ShowAlert(vueObj.$t("ErrorWhileProcessingRequest"), "failure", true, vueObj.$t("Alert"));
            });
        },
        Close: function () {  
            this.$parent.IsCDCCode = false;
        },
        AddCDCCode: function() {
            var vm = this;
            vm.isLoading = true;
            // Open Add CDC Code dialog - matching MVC: CDCCode action
            var url = `cdcCodeId=0&rowNo=&clientId=${vm.ClientId}&additionalId=${vm.additionalId}`;
            locateBillingService.GetCDCCode(url).then(response => {
                vm.isLoading = false;
                // TODO: Open Add CDC Code dialog component
                // For now, show alert - user needs to create AddCDCCode component
                vm.ShowAlert(vm.$t('AddCDCCodeFunctionality'), "info", true, vm.$t("Alert"));
            }).catch(error => {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), "failure", true, vm.$t("Alert"));
            });
        },
        EditCDCCode: function(item, index) {
            var vm = this;
            vm.isLoading = true;
            // Open Edit CDC Code dialog - matching MVC: GETCDCCode action
            var url = `CDCCodeId=${item.CDC_ID}&rowNo=&clientId=${vm.ClientId}&additionalId=${vm.additionalId}`;
            locateBillingService.GetCDCCode(url).then(response => {
                vm.isLoading = false;
                // TODO: Open Edit CDC Code dialog component
                // For now, show alert - user needs to create EditCDCCode component
                vm.ShowAlert(vm.$t('EditCDCCodeFunctionality'), "info", true, vm.$t("Alert"));
            }).catch(error => {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), "failure", true, vm.$t("Alert"));
            });
        },
        DeleteMultipleCDCCode: function() {
            var vm = this;
            // Get selected items from checkboxes
            var selectedIds = vm.selectedItems.map(item => item.CDC_ID).join(',');
            
            if (!selectedIds || selectedIds.length === 0) {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"), "failure", true, vm.$t("Alert"));
                return;
            }
            
            // Confirm delete - matching MVC confirmR function
            if (confirm(vm.$t("ConfirmDelete"))) {
                vm.isLoading = true;
                // Delete CDC Code - matching MVC: DeleteCDCCode action
                var postData = { ids: selectedIds };
                locateBillingService.DeleteCDCCode(postData).then(response => {
                    vm.isLoading = false;
                    if (response.data.msg === "success") {
                        vm.ShowAlert(response.data.status || vm.$t('RecordDeletedSuccessfully'), "success", true, vm.$t("Alert"));
                        vm.selectedItems = [];
                        vm.FetchData();
                        // Refresh parent if needed - matching MVC: GetCDCCodeString call
                        if (vm.$parent && vm.$parent.refreshCDCCodeString) {
                            vm.$parent.refreshCDCCodeString();
                        }
                    } else {
                        vm.ShowAlert(response.data.status || vm.$t("ErrorWhileProcessingRequest"), "failure", true, vm.$t("Alert"));
                    }
                }).catch(error => {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), "failure", true, vm.$t("Alert"));
                });
            }
        },
        onCheckboxChange: function(selectedItems) {
            // Handle checkbox selection change
            var vm = this;
            vm.selectedItems = selectedItems;
            // Enable/disable delete button based on selection
            var deleteButton = vm.listheaderbuttons.find(b => b.callbackfunction === 'DeleteMultipleCDCCode');
            if (deleteButton) {
                deleteButton.isdisabled = !selectedItems || selectedItems.length === 0;
            }
        }
    }
}
</script>
    
    
    